    const depths = this.lineageData?.depths || {};
    for (const key of Object.keys(depths)) {
      const num = parseFloat(key);
      if (!isNaN(num) && num > maxDepth) {
        maxDepth = num;
      }
    }
    return maxDepth;
  }

